// learningRow is the JSON output shape for `learnings list`.
type learningRow struct {
	QueryPattern string    `json:"query_pattern"`
	ResourceIDs  []string  `json:"resource_ids"`
	ResourceType string    `json:"resource_type,omitempty"`
	Venue        string    `json:"venue,omitempty"`
	Action       string    `json:"action"`
	Confidence   int       `json:"confidence"`
	Source       string    `json:"source"`
	UpdatedAt    time.Time `json:"updated_at"`
}

// listLearningsFilter narrows listLearnings.
type listLearningsFilter struct {
	Query         string
	Source        string
	ResourceID    string
	Action        string
	MinConfidence int
	Limit         int
}

// listLearnings reads rows from the search_learnings table the v3
// schema provides. Filters are AND'd. resource_id filter matches when
// the JSON array contains the supplied id.
func listLearnings(ctx context.Context, db *sql.DB, f listLearningsFilter) ([]learningRow, error) {
	if db == nil {
		return nil, errors.New("listLearnings: db is nil")
	}
	clauses := []string{}
	args := []any{}
	if strings.TrimSpace(f.Query) != "" {
		clauses = append(clauses, "query_pattern LIKE ?")
		args = append(args, "%"+f.Query+"%")
	}
	if strings.TrimSpace(f.Source) != "" {
		clauses = append(clauses, "source = ?")
		args = append(args, f.Source)
	}
	if strings.TrimSpace(f.Action) != "" {
		clauses = append(clauses, "action = ?")
		args = append(args, f.Action)
	}
	if f.MinConfidence > 0 {
		clauses = append(clauses, "confidence >= ?")
		args = append(args, f.MinConfidence)
	}
	where := ""
	if len(clauses) > 0 {
		where = "WHERE " + strings.Join(clauses, " AND ")
	}
	limit := f.Limit
	if limit <= 0 {
		limit = 200
	}
	args = append(args, limit)

	q := fmt.Sprintf(`SELECT query_pattern, COALESCE(resource_ids, '[]'), resource_type,
			COALESCE(venue, ''), COALESCE(action, ''), confidence, COALESCE(source, ''), updated_at
		FROM search_learnings
		%s
		ORDER BY updated_at DESC
		LIMIT ?`, where)

	rows, err := db.QueryContext(ctx, q, args...)
	if err != nil {
		return nil, fmt.Errorf("listLearnings query: %w", err)
	}
	defer rows.Close()

	out := make([]learningRow, 0)
	for rows.Next() {
		var (
			pattern    string
			idsJSON    string
			rt         string
			venue      string
			action     string
			confidence int
			source     string
			updatedAt  time.Time
		)
		if err := rows.Scan(&pattern, &idsJSON, &rt, &venue, &action, &confidence, &source, &updatedAt); err != nil {
			return nil, fmt.Errorf("listLearnings scan: %w", err)
		}
		var ids []string
		_ = json.Unmarshal([]byte(idsJSON), &ids)
		if f.ResourceID != "" {
			matched := false
			for _, id := range ids {
				if id == f.ResourceID {
					matched = true
					break
				}
			}
			if !matched {
				continue
			}
		}
		out = append(out, learningRow{
			QueryPattern: pattern,
			ResourceIDs:  ids,
			ResourceType: rt,
			Venue:        venue,
			Action:       action,
			Confidence:   confidence,
			Source:       source,
			UpdatedAt:    updatedAt,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("listLearnings rows: %w", err)
	}
	return out, nil
}

func newLearningsListCmd(flags *rootFlags) *cobra.Command {
	var queryFilter string
	var sourceFilter string
	var resourceFilter string
	var actionFilter string
	var minConf int
	var limit int
	var dbPath string
	var warningsOnly bool

	cmd := &cobra.Command{
		Use:   "list",
		Short: "List recorded learnings",
		Example: `  contact-goat-pp-cli learnings list --agent
  contact-goat-pp-cli learnings list --query "<substring>"
  contact-goat-pp-cli learnings list --warnings --agent`,
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if learnDryRunOK(flags) {
				return nil
			}
			if warningsOnly {
				var filterIDs []string
				if strings.TrimSpace(resourceFilter) != "" {
					filterIDs = []string{resourceFilter}
				}
				entries, err := learn.ReadTeachLogWarnings(filterIDs...)
				if err != nil {
					return fmt.Errorf("learnings list --warnings: %w", err)
				}
				if entries == nil {
					entries = []learn.TeachLogEntry{}
				}
				if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
					return learnPrintJSON(cmd.OutOrStdout(), map[string]any{
						"warnings": entries,
					}, flags)
				}
				if len(entries) == 0 {
					fmt.Fprintln(cmd.OutOrStdout(), "(no teach.log warnings recorded)")
					return nil
				}
				for _, e := range entries {
					fmt.Fprintf(cmd.OutOrStdout(), "%s\t%s\t%s\tsuggested=%s\n",
						e.TS, e.Warning, e.Resource, e.Suggested)
				}
				return nil
			}

			dbPath = learnDBPath(dbPath)
			s, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("learnings list: %w", err)
			}
			defer s.Close()

			rows, err := listLearnings(cmd.Context(), s.DB(), listLearningsFilter{
				Query:         queryFilter,
				Source:        sourceFilter,
				ResourceID:    resourceFilter,
				Action:        actionFilter,
				MinConfidence: minConf,
				Limit:         limit,
			})
			if err != nil {
				return fmt.Errorf("learnings list: %w", err)
			}

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return learnPrintJSON(cmd.OutOrStdout(), rows, flags)
			}
			if len(rows) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "(no learnings recorded)")
				return nil
			}
			for _, r := range rows {
				fmt.Fprintf(cmd.OutOrStdout(), "%s\t%s\t%v\tconf=%d\tsource=%s\n",
					r.QueryPattern, r.Action, r.ResourceIDs, r.Confidence, r.Source)
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&queryFilter, "query", "", "Filter by normalized query substring")
	cmd.Flags().StringVar(&sourceFilter, "source", "", "Filter by source (taught | manual-forget)")
	cmd.Flags().StringVar(&resourceFilter, "resource", "", "Filter by resource_id")
	cmd.Flags().StringVar(&actionFilter, "action", "", "Filter by action (boost | hide | alias_of)")
	cmd.Flags().IntVar(&minConf, "min-confidence", 0, "Filter by minimum confidence")
	cmd.Flags().IntVar(&limit, "limit", 200, "Maximum rows to return")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: standard cache location)")
	cmd.Flags().BoolVar(&warningsOnly, "warnings", false, "Return teach-time warnings from teach.log instead of stored learning rows")
	return cmd
}

// forgetLearningsFilter narrows forgetLearnings.
type forgetLearningsFilter struct {
	Query      string
	ResourceID string
	Action     string
	All        bool
}

// forgetLearnings deletes rows matching the filter and returns the
// count removed. Requires at least one of ResourceID, Action, or All;
// otherwise an empty filter would silently wipe every row for the
// supplied query. The supplied query is normalized through cfg before
// matching against the stored query_pattern column.
func forgetLearnings(ctx context.Context, db *sql.DB, cfg *entities.Config, f forgetLearningsFilter) (int64, error) {
	if db == nil {
		return 0, errors.New("forgetLearnings: db is nil")
	}
	if strings.TrimSpace(f.Query) == "" {
		return 0, errors.New("forgetLearnings: query is required")
	}
	if !f.All && strings.TrimSpace(f.ResourceID) == "" && strings.TrimSpace(f.Action) == "" {
		return 0, errors.New("pass --all, --resource, or --action")
	}

	normalized := learn.Normalize(f.Query, cfg).NonEntityNormalized
	// Find candidate rows by normalized query first, then filter in-Go
	// for resource_id (which lives inside the JSON array column).
	rows, err := db.QueryContext(ctx,
		`SELECT rowid, COALESCE(resource_ids, '[]'), COALESCE(action, '') FROM search_learnings WHERE query_pattern = ?`,
		normalized,
	)
	if err != nil {
		return 0, fmt.Errorf("forgetLearnings query: %w", err)
	}
	type victim struct {
		rowID int64
		ids   []string
	}
	var victims []victim
	for rows.Next() {
		var (
			rowID   int64
			idsJSON string
			action  string
		)
		if err := rows.Scan(&rowID, &idsJSON, &action); err != nil {
			rows.Close()
			return 0, fmt.Errorf("forgetLearnings scan: %w", err)
		}
		if f.Action != "" && action != f.Action {
			continue
		}
		var ids []string
		_ = json.Unmarshal([]byte(idsJSON), &ids)
		if f.ResourceID != "" {
			matched := false
			for _, id := range ids {
				if id == f.ResourceID {
					matched = true
					break
				}
			}
			if !matched {
				continue
			}
		}
		victims = append(victims, victim{rowID: rowID, ids: ids})
	}
	rows.Close()
	if err := rows.Err(); err != nil {
		return 0, fmt.Errorf("forgetLearnings rows: %w", err)
	}

	var deleted int64
	for _, v := range victims {
		// Targeted forget: drop just the matching ID; if the row's IDs
		// becomes empty, drop the row entirely. --all bypasses the
		// partial path and drops the row outright.
		if f.All || f.ResourceID == "" {
			res, err := db.ExecContext(ctx, `DELETE FROM search_learnings WHERE rowid = ?`, v.rowID)
			if err != nil {
				return deleted, fmt.Errorf("forgetLearnings delete: %w", err)
			}
			n, _ := res.RowsAffected()
			deleted += n
			continue
		}
		remaining := v.ids[:0]
		for _, id := range v.ids {
			if id != f.ResourceID {
				remaining = append(remaining, id)
			}
		}
		if len(remaining) == 0 {
			res, err := db.ExecContext(ctx, `DELETE FROM search_learnings WHERE rowid = ?`, v.rowID)
			if err != nil {
				return deleted, fmt.Errorf("forgetLearnings delete: %w", err)
			}
			n, _ := res.RowsAffected()
			deleted += n
			continue
		}
		newJSON, _ := json.Marshal(remaining)
		if _, err := db.ExecContext(ctx,
			`UPDATE search_learnings SET resource_ids = ?, updated_at = ? WHERE rowid = ?`,
			string(newJSON), time.Now().UTC(), v.rowID,
		); err != nil {
			return deleted, fmt.Errorf("forgetLearnings update: %w", err)
		}
		deleted++
	}
	return deleted, nil
}

func newLearningsForgetCmd(flags *rootFlags, learnCfg *entities.Config) *cobra.Command {
	var resourceArg string
	var actionArg string
	var all bool
	var dbPath string

	cmd := &cobra.Command{
		Use:   "forget <query>",
		Short: "Delete learnings matching a query (use --all to wipe every rule for that query)",
		Long: `Removes rows from the search_learnings table so a bad teach can be
undone without dropping the whole DB.

Requires at least one of --resource, --action, or --all.`,
		Example: `  contact-goat-pp-cli learnings forget "<question>" --resource <id>
  contact-goat-pp-cli learnings forget "<question>" --all`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return cmd.Help()
			}
			if learnDryRunOK(flags) {
				return nil
			}
			query := strings.Join(args, " ")
			dbPath = learnDBPath(dbPath)
			s, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("learnings forget: %w", err)
			}
			defer s.Close()

			n, err := forgetLearnings(cmd.Context(), s.DB(), learnCfg, forgetLearningsFilter{
				Query:      query,
				ResourceID: resourceArg,
				Action:     actionArg,
				All:        all,
			})
			if err != nil {
				return usageErr(fmt.Errorf("learnings forget: %w", err))
			}
			_ = appendLearningsAudit(map[string]any{
				"action":       "forget",
				"query":        query,
				"filter":       map[string]any{"resource": resourceArg, "action": actionArg, "all": all},
				"rows_deleted": n,
			})

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return learnPrintJSON(cmd.OutOrStdout(), map[string]any{
					"deleted": n,
					"query":   query,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "forgot %d learning(s) for %q\n", n, query)
			return nil
		},
	}
	cmd.Flags().StringVar(&resourceArg, "resource", "", "Delete only the rule for this resource_id")
	cmd.Flags().StringVar(&actionArg, "action", "", "Delete only rules with this action (boost | hide | alias_of)")
	cmd.Flags().BoolVar(&all, "all", false, "Delete every rule for the supplied query")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: standard cache location)")
	return cmd
}

// newTeachPatternCmd installs a manual generalization pattern. The
// recall path uses patterns to substitute entities into resource
// templates.
func newTeachPatternCmd(flags *rootFlags) *cobra.Command {
	var queryTemplate string
	var resourceTemplate string
	var resourceType string
	var venue string
	var strategy string
	var entityKind string
	var dbPath string

	cmd := &cobra.Command{
		Use:   "teach-pattern",
		Short: "Install a manual generalization pattern (query_template, resource_template, entity_kind)",
		Long: `Adds one row to search_patterns. The recall path uses patterns to
substitute live query entities into a resource template, so a pattern
with query_template="odds {entity} wins world cup" and
resource_template="WORLDCUP-{entity:country}" generalizes one teach
into a whole family.`,
		Example: `  contact-goat-pp-cli teach-pattern \
    --query-template "odds {entity} wins world cup" \
    --resource-template "WORLDCUP-{entity:country}" \
    --resource-type "events" \
    --entity-kind "country" \
    --strategy substitute`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if learnDryRunOK(flags) {
				return nil
			}
			if noLearnActive(flags) {
				return nil
			}
			if strings.TrimSpace(queryTemplate) == "" {
				return usageErr(fmt.Errorf("--query-template is required"))
			}
			if strings.TrimSpace(resourceTemplate) == "" {
				return usageErr(fmt.Errorf("--resource-template is required"))
			}
			if strings.TrimSpace(resourceType) == "" {
				return usageErr(fmt.Errorf("--resource-type is required"))
			}
			if strings.TrimSpace(entityKind) == "" {
				return usageErr(fmt.Errorf("--entity-kind is required"))
			}
			if strategy == "" {
				strategy = patterns.StrategySubstitute
			}
			dbPath = learnDBPath(dbPath)
			s, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("teach-pattern: %w", err)
			}
			defer s.Close()

			inserted, err := patterns.Upsert(s.DB(), patterns.Pattern{
				QueryTemplate:    queryTemplate,
				ResourceTemplate: resourceTemplate,
				ResourceType:     resourceType,
				Venue:            venue,
				Strategy:         strategy,
				EntityKind:       entityKind,
				Source:           patterns.SourceTaught,
			})
			if err != nil {
				return fmt.Errorf("teach-pattern: %w", err)
			}
			return learnPrintJSON(cmd.OutOrStdout(), map[string]any{
				"recorded":          true,
				"newly_inserted":    inserted,
				"query_template":    queryTemplate,
				"resource_template": resourceTemplate,
				"resource_type":     resourceType,
				"venue":             venue,
				"strategy":          strategy,
				"entity_kind":       entityKind,
			}, flags)
		},
	}
	cmd.Flags().StringVar(&queryTemplate, "query-template", "", "Query template with {entity} placeholder (required)")
	cmd.Flags().StringVar(&resourceTemplate, "resource-template", "", "Resource template with typed entity slot, e.g. PREFIX-{entity:country} (required)")
	cmd.Flags().StringVar(&resourceType, "resource-type", "", "Resource type for substituted IDs (required)")
	cmd.Flags().StringVar(&venue, "venue", "", "Optional venue scope tag")
	cmd.Flags().StringVar(&strategy, "strategy", "", "Substitution strategy: substitute | substitute-then-search-prefix (default substitute)")
	cmd.Flags().StringVar(&entityKind, "entity-kind", "", "Entity kind name registered in entity_lookups (required)")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: standard cache location)")
	return cmd
}

// newTeachLookupCmd installs a manual entity-lookup row.
func newTeachLookupCmd(flags *rootFlags) *cobra.Command {
	var kind string
	var canonical string
	var alias string
	var dbPath string

	cmd := &cobra.Command{
		Use:   "teach-lookup",
		Short: "Install a manual entity-lookup row (kind, canonical, alias)",
		Long: `Adds one row to entity_lookups. Used by the recall path's pattern
engine to substitute aliases for canonical names at substitution time.
Computed kinds (lowercase, uppercase, kebab-case, capitalize-first, slug)
cannot be taught — they are derived from the canonical input.`,
		Example: `  contact-goat-pp-cli teach-lookup --kind country --canonical "United States" --alias USA`,
		RunE: func(cmd *cobra.Command, args []string) error {
			if learnDryRunOK(flags) {
				return nil
			}
			if noLearnActive(flags) {
				return nil
			}
			if strings.TrimSpace(kind) == "" {
				return usageErr(fmt.Errorf("--kind is required"))
			}
			if strings.TrimSpace(canonical) == "" {
				return usageErr(fmt.Errorf("--canonical is required"))
			}
			if strings.TrimSpace(alias) == "" {
				return usageErr(fmt.Errorf("--alias is required"))
			}
			if lookups.IsComputedKind(kind) {
				return usageErr(fmt.Errorf("--kind %q is a computed kind and cannot be taught", kind))
			}
			dbPath = learnDBPath(dbPath)
			s, err := store.Open(dbPath)
			if err != nil {
				return fmt.Errorf("teach-lookup: %w", err)
			}
			defer s.Close()

			if err := lookups.Upsert(s.DB(), kind, canonical, alias, "taught"); err != nil {
				return fmt.Errorf("teach-lookup: %w", err)
			}
			return learnPrintJSON(cmd.OutOrStdout(), map[string]any{
				"recorded":  true,
				"kind":      kind,
				"canonical": canonical,
				"alias":     alias,
			}, flags)
		},
	}
	cmd.Flags().StringVar(&kind, "kind", "", "Entity kind, e.g. country, team (required, must not be a computed kind)")
	cmd.Flags().StringVar(&canonical, "canonical", "", "Canonical entity name (required)")
	cmd.Flags().StringVar(&alias, "alias", "", "Alias that should resolve to the canonical (required)")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (default: standard cache location)")
	return cmd
}
